import{_ as t,o as r,c,d as e,e as a}from"./app-a82ee0e5.js";const n={},s=e("h2",{id:"react",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#react","aria-hidden":"true"},"#"),a(" react")],-1),o=e("h3",{id:"jsx",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#jsx","aria-hidden":"true"},"#"),a(" JSX")],-1),d=e("p",null,[a("JSX其实就是一个描述UI结构的JavaScript对象（虚拟DOM），当他转化成页面的时候，首先会经过babel和react进行编译，变成JavaScript，然后再经由ReactDOM.render转化成DOM 1、为什么不直接转换成DOM 先转化成JS，方便后续有变化的时候进行计算，如果直接转换成DOM，在有变化的时候就要直接操作DOM，这样就会导致需要重排很多次，性能比较不好 再者就是，不同的渲染器会将虚拟DOM转成对应平台的元素，不一定是浏览器的DOM。 2、react的render为什么只能返回单一的一个JSX元素，不能并列？ JSX经编译后本质上是一个函数调用，JS的return只能返回一个值，虚拟DOM是一个树状结构，只能有一个根节点。 React 的虚拟 DOM 是一棵 "),e("strong",null,"树状结构"),a("，树必须有且仅有一个根节点。如果允许并列多个元素，虚拟 DOM 会变成 “森林”（多棵树），这会导致： - Diff 算法无法高效对比（树的遍历依赖单一根节点） - 状态管理、生命周期等逻辑难以统一附着在 “多个根” 上 - 与 React 的协调（Reconciliation）机制冲突（需要明确的根节点作为更新起点）")],-1),i=[s,o,d];function _(h,l){return r(),c("div",null,i)}const f=t(n,[["render",_],["__file","react.html.vue"]]);export{f as default};
